import type { App, Component, ComponentInstance, VNodeProps } from 'vue'
import type { ContentScriptContext, ShadowRootContentScriptUiOptions } from 'wxt/client'
import { usePinia } from '@/src/vue/pinia'
import { SharedSentry } from '@/utils/sentry'

/** Share ContentScriptContext across code */
export const useContentScriptContext = createSharedComposable((context?: ContentScriptContext) => {
  if (!context)
    throw new Error('useContentScriptContext called without providing initial context')

  return context
})

/** Mounts a vue app using shadow root ui */
export function defineContentUI<TMounted extends App<Element>>(options: ShadowRootContentScriptUiOptions<TMounted>) {
  const ctx = useContentScriptContext()
  return createShadowRootUi(ctx, {
    onRemove(app) {
      app?.unmount()
    },

    ...options
  })
}

/**
 * Mounts a component using shadow root ui.
 * Provides less flexibility than {@link defineContentUI}
 */
export function defineContentUIApp<T extends Component>(
  App: Component,
  options: Omit<ShadowRootContentScriptUiOptions<App<Element>>, 'onMount' | 'onRemove'> & {
    /** Props for root component */
    props?: Record<string, unknown> & ComponentInstance<T>['$props'] & VNodeProps
  }
) {
  loadContentUIFonts()

  return defineContentUI({
    ...options,

    onMount(wrapper) {
      // Apply google fonts
      wrapper.style.fontFamily = 'Outfit, Inter, "Google Sans", Roboto, RobotoDraft, Helvetica, Arial, sans-serif'

      const app = createApp(App, options.props)
        .use(usePinia())

      // Handle errors
      app.config.errorHandler = (error, vm, info) => {
        console.error('Error occurred in vue', { err: error, vm, info })
        SharedSentry.captureError(error, {
          captureContext: (scope) => {
            scope.setExtra('info', info)
            return scope
          }
        })
      }

      app.mount(wrapper)
      return app
    },

    onRemove(app) {
      app?.unmount()
    }
  })
}

/** Loads font in the content ui */
function loadContentUIFonts() {
  interface WindowWithFonts extends Window {
    HAS_INSERTED_FONTS?: boolean
  }

  const root: WindowWithFonts = window.top || window

  if (root.HAS_INSERTED_FONTS)
    return

  const link = document.createElement('link')
  link.rel = 'stylesheet'
  link.href = 'https://fonts.googleapis.com/css2?family=Outfit:wght@100..900&display=swap'

  root.document.head.appendChild(link)
  root.HAS_INSERTED_FONTS = true
}

/** Open extension popup page from content script */
export function openPopupPage() {
  return chrome.runtime.sendMessage('open-popup')
}
