import type z from 'zod'
import { Auth } from '@/src/http'

import {
  BrowserClient,
  defaultStackParser,
  type EventHint,
  getDefaultIntegrations,
  makeFetchTransport,
  Scope
} from '@sentry/vue'

export class SharedSentry {
  static #scope?: Scope

  static get scope(): Scope {
    let scope = this.#scope

    if (!scope) {
      // filter integrations that use the global variable
      const integrations = getDefaultIntegrations({}).filter(
        (defaultIntegration) => {
          return !['BrowserApiErrors', 'Breadcrumbs', 'GlobalHandlers'].includes(
            defaultIntegration.name
          )
        }
      )

      const client = new BrowserClient({
        dsn: 'https://ad587efa7b7e50aaa728bf3d4a1f4728@o483297.ingest.us.sentry.io/4507752452980736',
        transport: makeFetchTransport,
        stackParser: defaultStackParser,
        integrations,
        enabled: true,
        debug: import.meta.env.DEV,
        sampleRate: 1.0,
        normalizeDepth: 6,
        release: import.meta.env.SENTRY_VERSION
      })

      scope = new Scope()
      scope.setClient(client)

      client.init() // initializing has to be done after setting the client on the scope

      this.#scope = scope
    }

    // Update current user
    const user = Auth.user.value

    if (user && scope.getUser()?.id !== user.id) {
      console.debug('AutoGmail: sentry identify', user)
      scope.setUser(user)
    }

    return scope
  }

  static captureError(error: unknown, hint?: EventHint) {
    this.scope.captureException(error, hint)
  }

  static captureMessage(...args: Parameters<Scope['captureMessage']>) {
    this.scope.captureMessage(...args)
  }

  static wrapFn<T extends () => any, Fallback>(fn: T, fallback: Fallback): ReturnType<T> | Fallback {
    try {
      return fn()
    }
    catch (error) {
      this.scope.captureException(error)
    }

    return fallback
  }

  /** Parses zod model */
  static zodParse<T extends z.ZodObject<any>>(model: T, data: unknown): z.infer<T> {
    try {
      return model.parse(data)
    }
    catch (error) {
      this.scope.captureException(error, {
        captureContext: (scope) => {
          scope.setExtra('model data', data)

          return scope
        }
      })

      return data as any
    }
  }
}
