import type { ComposeView, InboxSDK, MessageView, ThreadView } from '@inboxsdk/core'
import { Drafts, Signature } from '@/src/http'
import dateParser from 'any-date-parser'

export interface ComposeViewProps {
  view: ComposeView
  data: Drafts.IPayloadModel
}

function parseDate(input: string, locale: string): Date {
  try {
    return dateParser.fromString(input, locale)
  }

  catch (error) {
    console.error('Failed to parse date', error)
    return new Date()
  }
}

class GmailContextSignature {
  /** Native gmail signature. This is static and doesn't react to changes */
  native

  constructor(private view: ComposeView) {
    this.native = this.view.getBodyElement().querySelector('.gmail_signature')?.innerHTML
  }

  /** Returns signature from AutoGmail settings */
  getCustom() {
    return useUser().signature
  }

  /** Returns native or custom signature. Native is prioritized */
  get() {
    return this.native || this.getCustom()
  }

  /** Sets native or custom signature. Can be used refresh signature as well */
  append() {
    const input = this.get()

    if (input)
      Signature.append(this.view.getBodyElement(), input)
  }
}

export class GmailContext {
  constructor(
    readonly sdk: InboxSDK,
    readonly view: ComposeView,
    readonly thread?: ThreadView,
    readonly signature = new GmailContextSignature(view)
  ) {}

  /**
   * Draft Model data
   * - Data can change based on user action. So make sure to get the latest data for usage
   */
  getData() {
    const { sdk, view, thread } = this
    const locale = sdk.User.getLanguage().slice(0, 2) ?? 'en'

    console.debug('Using user locale', locale)

    const baseData: Partial<Drafts.IPayloadModel> = {
      subject: view.getSubject(),
      recipients: view.getToRecipients()
    }

    const dataset = thread
      // Thread based
      ? {
          ...baseData,
          threadID: view.getThreadID(),
          messages: thread.getMessageViews().map((item) => {
            const sender = item.getSender()
            const isSender = sender.emailAddress === sdk.User.getEmailAddress()

            return {
              sender,
              isSender,
              id: item.getMessageID(),
              date: parseDate(item.getDateString(), locale),
              text: (item.getBodyElement().textContent || '').trim()
            }
          })
        }

      // New email without thread
      : { ...baseData, threadID: '', messages: [] }

    return SharedSentry.zodParse(Drafts.PayloadModel, dataset)
  }

  get hasDraft() {
    const body = this.view.getBodyElement()
    const lines = body.innerText.split('\n')
    const hasLines = lines.length > 0
    let firstLineIndex = 0

    const hasGemini = body.children[0]?.getAttribute?.('contenteditable') === 'false'
      || ['Help me write', '⌥ H', 'Alt + H'].some(r => lines[0].includes(r))

    // Handle `Help me write` edge-case
    if (lines.length === 2 && hasGemini) {
      firstLineIndex = 1
    }

    const firstLineNotEmpty = lines[firstLineIndex]?.trim() !== ''
    const hasDraft = hasLines && firstLineNotEmpty
    const context = { lines, hasLines, hasGemini, firstLineNotEmpty }

    console.debug('🤖 Compose hasDraft', context)

    if (hasDraft) {
      SharedSentry.captureMessage('user has draft', 'info', {
        captureContext: (scope) => {
          scope.setExtra('data', context)
          return scope
        }
      })
    }

    return hasDraft
  }

  /** Whether compose view has ai draft */
  get hasAIDraft() {
    return Drafts.hasAIDraft(this.view.getBodyElement())
  }

  /** Returns max height of editor */
  get editorMaxHeight() {
    const body = this.view.getElement()
    const rect = body.getBoundingClientRect()

    return rect.height * 0.4
  }

  getDraftContainer() {
    return this.view.getBodyElement()
  }

  getDraftContent({ stripSignatures = false } = {}) {
    let body = this.getDraftContainer().cloneNode(true) as HTMLElement

    if (stripSignatures) {
      body = Signature.remove(body)
    }

    return { html: body.innerHTML, text: body.textContent || '' }
  }

  setDraft(html: string): void {
    animateDOM(() => {
      this.getDraftContainer().innerHTML = html
    })
  }

  /** Uses AI to generate drafts */
  async generateDrafts({
    instructions = ''
  } = {}) {
    const payload = structuredClone(this.getData())

    // Include custom message if available
    if (instructions) {
      payload.customMessage = instructions
      payload.draft = this.getDraftContent({ stripSignatures: true }).text
    }

    const result = await Drafts.generate(payload, { signature: this.signature.native })
    Analytics.track('Draft generated', result)

    return result
  }

  // Hooks
  async onEmailImported(onSuccess: VoidFunction) {
    const { view, thread } = this

    view.addListener('sent', async (message) => {
      const data: Drafts.IImportEmailModel = {
        messageID: null,
        emailID: await message.getMessageID(),
        threadID: await message.getThreadID(),
        sender: view.getFromContact().emailAddress,
        subject: view.getSubject(),
        body: view.getTextContent(),
        recipients: view.getToRecipients()
      }

      const threadMessage = thread?.getMessageViews().at(-1)

      if (threadMessage) {
        data.recipients = await threadMessage.getRecipientsFull()
        data.messageID = await getMessageId(threadMessage)
      }

      console.debug('⚡ Importing email', data)

      onSuccess()
      await Drafts.importEmail(data)
      Analytics.track('Email imported', data)
    })
  }
}

/** Returns a message id with format like this `<CAKKYa_t-kvwGotzi4aYi20ijx=7ragiSYTDoofqBdAyhLP2NjQ@mail.gmail.com>` */
export async function getMessageId(messageView: MessageView): Promise<string | null> {
  const ik = document.head.getAttribute('data-inboxsdk-ik-value')
  const messageId = messageView.getBodyElement().closest('div[data-message-id]')?.getAttribute('data-message-id')?.slice(1)

  if (!ik || !messageId) {
    console.warn('getMessageId: ik or messageId not found')
    return null
  }

  try {
    const url = `https://mail.google.com/mail/u/0?ik=${ik}&view=om&permmsgid=${encodeURIComponent(messageId)}`
    const data = await fetch(url).then(i => i.text())
    const doc = new DOMParser().parseFromString(data, 'text/html')
    const id = doc.querySelector('.message_id')?.textContent || null

    return id
  }
  catch (error) {
    console.warn('getMessageId: Failed to parse message id', error)
  }

  return null
}
