<script lang="ts" setup>
const props = defineProps<{
  tag?: keyof HTMLElementTagNameMap
  disabled?: boolean
  placeholder?: string
  inputClass?: string
  maxlength?: number
  onUpdate?: (value: string) => void
}>()

const element = ref<HTMLElement>()
const modelValue = defineModel<string>()

// Methods
function getRef(callback: (params: { node: HTMLElement, text: string, setText: (text: string) => void }) => void) {
  const node = element.value

  if (!node)
    return

  const text = node.textContent || ''
  const setText = (content: string) => node.textContent = content

  callback({ node, text, setText })

  // Remove empty br tag
  if (node.innerHTML === '<br>') {
    node.textContent = ''
  }
}

function onKeyPress(event: KeyboardEvent) {
  getRef(({ text }) => {
    const { maxlength } = props

    if (maxlength && text.length > maxlength)
      event.preventDefault()
  })
}

function update() {
  getRef(({ text }) => {
    modelValue.value = text
    props.onUpdate?.(text)
  })
}

// Watch for outside modeValue changes
watchEffect(() =>
  getRef(({ text, setText }) => {
    const newValue = modelValue.value

    if (newValue !== text)
      setText(newValue ?? '')
  })
)
</script>

<template>
  <span
    v-once
    ref="element"
    tabindex="0"
    class="empty:before:content-[attr(placeholder)]"
    :class="inputClass"
    :placeholder
    :contenteditable="!disabled"
    @keypress="onKeyPress"
    @input="update"
    v-text="modelValue"
  />
</template>
