import ToastServiceUI, { type ToastItem } from './toast-service.ui.vue'

export const useToastService = createSharedComposable(() => {
  console.debug('useToastService: Registered')

  const items = ref<ToastItem[]>([])

  function show(toast: Omit<ToastItem, 'id'>) {
    const id = crypto.randomUUID()
    const data = { ...toast, id }

    // Add item
    items.value = [...items.value, data]

    // Remove after 3s
    setTimeout(() => {
      items.value = items.value.filter(item => item.id !== id)
    }, 5000)
  }

  // Mount UI
  async function register() {
    const ui = await defineContentUIApp(
      () => <ToastServiceUI items={items} class="py-2 mb-4" />,
      {
        name: 'onboarding-ui',
        position: 'overlay'
      }
    )

    ui.mount()
  }

  register()

  return { items, show }
})
