<script lang="ts" setup>
import type { GmailContext } from './ComposeView.utils'
import { useToastService } from '../../services/toast-service'
import ActionCTA from './shared/ActionCTA.vue'

const { context } = defineProps<{ context: GmailContext }>()

const settings = useSettings()
const user = useUser()
const toast = useToastService()

const state = shallowReactive({
  activeDraft: 2,

  /** Custom user instructions from Editor */
  instructions: '',

  showPaywall: false,
  showEditor: false
})

const isBlacklisted = computed(() =>
  !settings.autoDraft || context.view.getToRecipients()
    .some(contact => user.blacklist.includes(contact.emailAddress))
)

const { state: drafts, isLoading, execute: refresh } = useAsyncState<string[]>(
  // Generate 2 drafts
  () => generateDrafts(),
  [],
  {
    immediate: false,
    async onSuccess(drafts) {
      // Skip if there's content in the body
      if (!drafts.length || context.hasDraft && !state.instructions)
        return

      setDraft(0, { savePrevious: false })
    }
  }
)

const draftError = ref<{ error: string, message: string } | null>(null)

async function generateDrafts() {
  // Clear previous error
  draftError.value = null
  state.showEditor = false

  const customDraft: string = drafts.value.at(-1) ?? ''
  const result = await context.generateDrafts({
    instructions: state.instructions
  })

  if (result.error) {
    console.error('Failed to generate drafts', result.error)

    // Show paywall if user needs to upgrade
    state.showPaywall = result.error === 'upgrade_required'
    draftError.value = result as any

    return []
  }

  return [...result.drafts, customDraft]
}

async function generateInstructedDrafts() {
  await refresh()
  state.instructions = ''
}

function generateWithoutInstructions() {
  state.instructions = ''
  return refresh()
}

/** Clears the body if no index is provided */
function setDraft(index: number, {
  savePrevious = true
} = {}) {
  // Update current draft
  if (savePrevious) {
    drafts.value[state.activeDraft] = context.getDraftContent().html
  }

  state.activeDraft = index

  const input = drafts.value?.[index] ?? ''
  const draft = input.replaceAll('\n', '<br>')

  context.setDraft(draft)

  console.debug('Set draft', { index, draft })
  Analytics.track('Set draft', { index })
}

async function upgrade() {
  await user.openPaymentPage()
  await refresh()
}

onBeforeMount(async () => {
  await settings.$onLoaded

  const status = {
    hasThread: !!context.thread,
    hasDraft: context.hasDraft,
    isBlacklisted: isBlacklisted.value
  }

  console.debug('🤖 Showing UI', { status, data: context.getData() })
  Analytics.track('Showing compose ui', status)

  /**
   * Refresh draft signature if
   * - there's a draft
   * - it's a new compose email
   * - user is blacklisted
   */
  if (context.hasDraft || context.view.isForward() || !context.thread || isBlacklisted.value) {
    context.signature.append()
    state.showEditor = true
  }

  // Load drafts
  else {
    refresh()
  }

  // Attach events
  context.onEmailImported(() => {
    toast.show({
      title: 'Email Imported',
      subtitle: 'Great! Your AI is getting better with every email you send',
      action: { label: 'View my AI', callback: openPopupPage }
    })
  })
})
</script>

<template>
  <div class="w-max">
    <Transition name="appear" mode="out-in">
      <ActionCTA v-if="isLoading" loader>
        Writing {{ state.instructions ? 'drafts using instructions...' : 'drafts...' }}
      </ActionCTA>

      <ActionCTA v-else-if="draftError?.error === 'upgrade_required'" action-label="Upgrade Now" @action-click="upgrade">
        {{ draftError?.message ?? 'Subscribe to keep using Auto Gmail' }}
      </ActionCTA>

      <ActionCTA v-else-if="state.showEditor" unstyled content-class="h-46px w-320px flex-center">
        <div
          class="editor-input z-1000 p-3 gap-10px min-h-full grid grid-cols-[1fr_max-content] absolute inset-0 bottom-unset text-sm bg-white rounded border-1 border-solid border-neutral/12 focus-within:border-neutral/30 overflow-y-auto"
          :style="{ maxHeight: `${context.editorMaxHeight}px` }"
        >
          <ContentModel
            v-model="state.instructions"
            class="border-none outline-none not-focus:font-light not-focus:line-clamp-1"
            placeholder="Write instructions for Auto Gmail here"
            @click.stop
          />

          <div class="gap-inherit flex-center h-max sticky top-3px mt-3px">
            <button
              :disabled="!state.instructions"
              class="i-heroicons:paper-airplane-solid size-4 text-neutral/40 not-disabled-hover:text-neutral"
              @click="generateInstructedDrafts"
            />

            <button class="i-mdi:close size-4 text-neutral/40 hover:text-neutral" @click="state.showEditor = false" />
          </div>
        </div>

        <button
          v-if="!!context.thread"
          title="Auto generate draft"
          class="i-solar:magic-stick-3-bold-duotone size-5 ml-10px absolute left-full text-primary"
          @click="generateWithoutInstructions"
        />
      </ActionCTA>

      <ActionCTA v-else unstyled content-class="gap-10px flex-center">
        <button
          v-for="draft, index in drafts"
          :key="index"
          :class="{ active: state.activeDraft === index }"
          class="draft-tab"
          @click="setDraft(index)"
        >
          {{ index === 2 ? 'Custom' : `Draft ${index + 1}` }}
        </button>

        <!-- Edit button -->
        <button class="icon-button" @click="state.showEditor = true">
          <span class="i-heroicons-pencil-solid" />
        </button>
      </ActionCTA>
    </Transition>
  </div>
</template>

<style lang="sass" scoped>
.icon-button
  @apply size-7 flex-center rounded-full text-xs text-neutral/40 border-2 border-solid border-neutral/12 hover:text-neutral hover:border-neutral/20 active:scale-96 transition-colors

  & > span
    @apply block

.draft-tab
  @apply px-3 h-28px flex-center rounded text-13px font-light border-1 border-solid border-neutral/8 hover:border-neutral/50 active:scale-96 transition-[background-color,border-color,transform]
  @apply [&.active]:bg-hex-f1f1f1 [&.active]:border-transparent

.editor-input
  scrollbar-gutter: stable both-edges

  &::-webkit-scrollbar
    width: 3px

  &::-webkit-scrollbar-track
    background: #fff
    border-radius: 8px

  &::-webkit-scrollbar-thumb
    background: rgba(0, 0, 0, 0.2)
    border-radius: 8px

.appear
  &-enter-active,
  &-leave-active
    transition: all 250ms ease
    transition-properties: opacity, transform

  &-enter-from
    opacity: 0
    transform: translateX(-100px)

  &-leave-to
    opacity: 0
    transform: scale(0.95)

// ;
</style>
